501: 	if err := rest.BeforeCreate(e.CreateStrategy, ctx, obj); err != nil {
502: 		return nil, err
503: 	}
504: 	// at this point we have a fully formed object.  It is time to call the validators that the apiserver
505: 	// handling chain wants to enforce.
506: 	if createValidation != nil {
