522: 	if err != nil {
523: 		return nil, err
524: 	}
525: 	out := e.NewFunc()
526: 	if err := e.Storage.Create(ctx, key, obj, out, ttl, dryrun.IsDryRun(options.DryRun)); err != nil {
527: 		err = storeerr.InterpretCreateError(err, qualifiedResource, name)
