75: 	ctx context.Context, key string, destination runtime.Object, ignoreNotFound bool,
76: 	preconditions *storage.Preconditions, tryUpdate storage.UpdateFunc, dryRun bool, cachedExistingObject runtime.Object) error {
77: 	if dryRun {
78: 		var current runtime.Object
79: 		v, err := conversion.EnforcePtr(destination)
80: 		if err != nil {
81: 			return fmt.Errorf("unable to convert output object to pointer: %v", err)
82: 		}
83: 		if u, ok := v.Addr().Interface().(runtime.Unstructured); ok {
84: 			current = u.NewEmptyInstance()
