90: 		if err != nil {
91: 			return err
92: 		}
93: 		err = preconditions.Check(key, current)
94: 		if err != nil {
95: 			return err
96: 		}
97: 		rev, err := s.Versioner().ObjectResourceVersion(current)
98: 		if err != nil {
99: 			return err
100: 		}
101: 		updated, _, err := tryUpdate(current, storage.ResponseMeta{ResourceVersion: rev})
102: 		if err != nil {
103: 			return err
104: 		}
105: 		return s.copyInto(updated, destination)
106: 	}
107: 	return s.Storage.GuaranteedUpdate(ctx, key, destination, ignoreNotFound, preconditions, tryUpdate, cachedExistingObject)
